// Clear leftover data from previous runs
const staticData = $getWorkflowStaticData('global');
staticData.lessonResults = [];

const raw = $input.first().json.choices[0].message.content;
let clean = raw.replace(/```json|```/g, '').trim();
const jsonStart = clean.indexOf('{');
const jsonEnd = clean.lastIndexOf('}');
if (jsonStart !== -1 && jsonEnd !== -1) {
  clean = clean.substring(jsonStart, jsonEnd + 1);
}
let course;
try {
  course = JSON.parse(clean);
} catch(e) {
  course = {
    course_title: "Generated Course",
    modules: [
      { module_number: 1, module_title: "Module 1", topics: ["Topic 1"], learning_objectives: ["Objective 1"] },
      { module_number: 2, module_title: "Module 2", topics: ["Topic 2"], learning_objectives: ["Objective 2"] }
    ]
  };
}
return course.modules.map(module => ({
  json: {
    course_title: course.course_title,
    module_number: module.module_number,
    module_title: module.module_title,
    topics: Array.isArray(module.topics) ? module.topics.join(', ') : module.topics,
    learning_objectives: Array.isArray(module.learning_objectives) ? module.learning_objectives.join(', ') : module.learning_objectives
  }
}));

