const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.lessonResults) staticData.lessonResults = [];

let moduleTitle = "Module";
let moduleNumber = 1;
let courseTitle = "Course";

try {
  const editData = $('Edit Fields').first().json;
  moduleTitle = editData.stored_module_title || moduleTitle;
  moduleNumber = editData.stored_module_number || moduleNumber;
  courseTitle = editData.stored_course_title || courseTitle;
} catch(e) {}

if (!input.choices || !input.choices[0]) {
  staticData.lessonResults.push({
    module_title: moduleTitle,
    module_number: moduleNumber,
    course_title: courseTitle,
    lesson_content: "<p>Content generation failed.</p>",
    raw_content: "Content generation failed for: " + moduleTitle,
    status: "pending_review"
  });
} else {
  const content = input.choices[0].message.content;
  let html = content
    .replace(/^### (.*$)/gm, '<h3>$1</h3>')
    .replace(/^## (.*$)/gm, '<h2>$1</h2>')
    .replace(/^# (.*$)/gm, '<h1>$1</h1>')
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.*?)\*/g, '<em>$1</em>')
    .replace(/^- (.*$)/gm, '<li>$1</li>')
    .replace(/\n\n/g, '</p><p>')
    .replace(/\n/g, '<br>');
  html = '<p>' + html + '</p>';

  staticData.lessonResults.push({
    module_title: moduleTitle,
    module_number: moduleNumber,
    course_title: courseTitle,
    lesson_content: html,
    raw_content: content,
    status: "pending_review"
  });
}

return [{ json: { module_title: moduleTitle, module_number: moduleNumber, status: "processed" } }];

const aggregated = $input.first().json.data;
const staticData = $getWorkflowStaticData('global');
const lessonResults = staticData.lessonResults || [];
staticData.lessonResults = [];

const courseTitle = (lessonResults[0]?.course_title || aggregated[0]?.course_title || "Generated Course").replace(/^=+/, '').trim();

const sorted = lessonResults.sort((a,b) => Number(a.module_number) - Number(b.module_number));

// Clean function to remove all markdown symbols
function cleanText(text) {
  return (text || '')
    .replace(/#{1,6}\s/g, '')
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/`{1,3}/g, '')
    .replace(/^={3,}$/gm, '')
    .replace(/^-{3,}$/gm, '')
    .replace(/^>{1,}/gm, '')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .replace(/^=+/gm, '')
    .trim();
}

const combinedContent = sorted.map(item => {
  const content = cleanText(item.raw_content || item.clean_content || "Content unavailable");
  const title = cleanText(item.module_title || "Module");
  return `MODULE ${item.module_number}: ${cleanText(String(item.module_number))}. ${title}\n\n${content}\n\n\n`;
}).join('');

const fullDocContent = `COURSE: ${courseTitle}\n\nGenerated by CourseForge AI\nDate: ${new Date().toLocaleDateString()}\n\n${combinedContent}`;

const modules = sorted.map(item => ({
  module_number: item.module_number,
  module_title: cleanText(item.module_title),
  course_title: courseTitle,
  lesson_content: item.lesson_content,
  raw_content: cleanText(item.raw_content),
  status: "pending_review"
}));

return [{
  json: {
    message: "Courseware generated. Awaiting review.",
    total_modules: modules.length,
    course_title: courseTitle,
    combined_content: fullDocContent,
    modules: modules
  }
}];

